USE rb_order;
CREATE TABLE IF NOT EXISTS rb_order (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, product_id BIGINT NOT NULL, amount DECIMAL(10,2) NOT NULL DEFAULT 0, status TINYINT DEFAULT 0, custom_attribute TEXT, create_time DATETIME DEFAULT CURRENT_TIMESTAMP, update_time DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS rb_order_attribute (id BIGINT AUTO_INCREMENT PRIMARY KEY, order_id BIGINT NOT NULL, name VARCHAR(100) DEFAULT '', value VARCHAR(200) DEFAULT '', create_time DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
